-- Generado desde: Fincas datos/clientes fincas.xlsx
-- Clientes validos: 1074. Filas omitidas por no tener nombre: 29, 729.
begin;

on conflict (source_key) do update set
  source_row = excluded.source_row,
  external_code = excluded.external_code,
  name = excluded.name,
  tax_id = excluded.tax_id,
  address = excluded.address,
  postal_code = excluded.postal_code,
  city = excluded.city,
  country_code = excluded.country_code,
  updated_at = now();

select setval(
  'public.lasheras_clients_id_seq',
  greatest((select coalesce(max(id), 1) from public.lasheras_clients), 1)
);

commit;
